installer-gui-script.script:
function installationCheck() {
    // system.sysctl() returns the kernel value in its native type. For
    // hw.optional.arm64 that's a numeric 1 on Apple Silicon, not the
    // string '1'. Compare with loose equality so both numeric and string
    // return shapes are accepted, and check hw.machine as a fallback for
    // older macOS versions where hw.optional.arm64 may behave differently.
    var arm64 = system.sysctl('hw.optional.arm64');
    if (arm64 == 1) {                     // eslint-disable-line eqeqeq
        return true;
    }
    var machine = system.sysctl('hw.machine') || '';
    if (machine.indexOf('arm') === 0) {   // "arm64"
        return true;
    }
    my.result.title = 'Unsupported processor';
    my.result.message = 'Fleet EDR requires Apple Silicon (M1 or later).';
    my.result.type = 'Fatal';
    return false;
}

function volumeCheck() {
    var ver = system.version.ProductVersion.split('.');
    var major = parseInt(ver[0], 10);
    if (isNaN(major) || major < 13) {
        my.result.title = 'Unsupported macOS';
        my.result.message = 'Fleet EDR requires macOS 13 (Ventura) or later.';
        my.result.type = 'Fatal';
        return false;
    }
    return true;
}
